DROP TABLE IF EXISTS `lecture_uploads`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lecture_uploads` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `batch_id` varchar(128) COLLATE utf8mb4_general_ci NOT NULL,
  `lecture_id` varchar(128) COLLATE utf8mb4_general_ci NOT NULL,
  `status` varchar(32) COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'pending',
  `server_id` varchar(128) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `file_path` text COLLATE utf8mb4_general_ci,
  `file_size` bigint DEFAULT NULL,
  `upload_bytes` bigint DEFAULT NULL,
  `upload_total` bigint DEFAULT NULL,
  `upload_percent` float DEFAULT NULL,
  `ia_identifier` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `ia_url` text COLLATE utf8mb4_general_ci,
  `telegram_chat_id` varchar(128) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `telegram_message_id` varchar(128) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `telegram_file_id` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `error_text` text COLLATE utf8mb4_general_ci,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_upload_lecture` (`batch_id`,`lecture_id`),
  CONSTRAINT `fk_upload_lecture` FOREIGN KEY (`batch_id`, `lecture_id`) REFERENCES `lectures` (`batch_id`, `lecture_id`)
