DROP TABLE IF EXISTS `lectures`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `lectures` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `batch_id` varchar(128) COLLATE utf8mb4_general_ci NOT NULL,
  `lecture_id` varchar(128) COLLATE utf8mb4_general_ci NOT NULL,
  `course_id` bigint DEFAULT NULL,
  `subject_id` bigint DEFAULT NULL,
  `chapter_id` bigint DEFAULT NULL,
  `subject_slug` varchar(128) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `subject_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `chapter_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `lecture_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `start_time` varchar(64) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `chapter_total` int DEFAULT NULL,
  `display_order` int DEFAULT NULL,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `user_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_lecture_batch` (`batch_id`,`lecture_id`),
  KEY `idx_lecture_course` (`course_id`),
  KEY `idx_lecture_subject` (`subject_id`),
  KEY `idx_lecture_chapter` (`chapter_id`),
  CONSTRAINT `fk_lecture_chapter` FOREIGN KEY (`chapter_id`) REFERENCES `chapters` (`id`),
  CONSTRAINT `fk_lecture_course` FOREIGN KEY (`course_id`) REFERENCES `courses` (`id`),
  CONSTRAINT `fk_lecture_subject` FOREIGN KEY (`subject_id`) REFERENCES `subjects` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3292 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

